+"""
+Great Expectations JSON templates for all supported expectation types.
+Templates use placeholder values that get replaced with actual parameters.
+"""
+
+from typing import Dict, Any, List
+import json
+
+# Base template structure that all expectations inherit
+BASE_TEMPLATE = {
+    "expectation_type": "",
+    "kwargs": {},
+    "meta": {
+        "notes": {
+            "format": "markdown",
+            "content": ""
+        },
+        "conversion_notes": "",
+        "original_sql": "",
+        "confidence_score": 0.0
+    }
+}
+
+# Template registry for all supported expectation types
+GEX_TEMPLATES: Dict[str, Dict[str, Any]] = {
+
+    # Metadata Expectations
+    "expect_column_to_exist": {
+        "expectation_type": "expect_column_to_exist",
+        "kwargs": {
+            "column": "{column_name}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that column '{column_name}' exists in the table"
+            }
+        }
+    },
+
+    "expect_table_column_count_to_equal": {
+        "expectation_type": "expect_table_column_count_to_equal",
+        "kwargs": {
+            "value": "{column_count}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that table has exactly {column_count} columns"
+            }
+        }
+    },
+
+    # Row-Level Expectations
+    "expect_column_values_to_not_be_null": {
+        "expectation_type": "expect_column_values_to_not_be_null",
+        "kwargs": {
+            "column": "{column_name}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that all values in column '{column_name}' are not null"
+            }
+        }
+    },
+
+    "expect_column_values_to_be_in_set": {
+        "expectation_type": "expect_column_values_to_be_in_set",
+        "kwargs": {
+            "column": "{column_name}",
+            "value_set": "{value_set}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that all values in column '{column_name}' are in allowed set"
+            }
+        }
+    },
+
+    # Pattern Matching Expectations
+    "expect_column_values_to_match_like_pattern": {
+        "expectation_type": "expect_column_values_to_match_like_pattern",
+        "kwargs": {
+            "column": "{column_name}",
+            "like_pattern": "{pattern}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that values in column '{column_name}' match pattern '{pattern}'"
+            }
+        }
+    },
+
+    "expect_column_values_to_not_match_like_pattern": {
+        "expectation_type": "expect_column_values_to_not_match_like_pattern",
+        "kwargs": {
+            "column": "{column_name}",
+            "like_pattern": "{pattern}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that values in column '{column_name}' do not match pattern '{pattern}'"
+            }
+        }
+    },
+
+    # Aggregate Expectations
+    "expect_column_min_to_be_between": {
+        "expectation_type": "expect_column_min_to_be_between",
+        "kwargs": {
+            "column": "{column_name}",
+            "min_value": "{min_value}",
+            "max_value": "{max_value}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that minimum value of column '{column_name}' is between {min_value} and {max_value}"
+            }
+        }
+    },
+
+    "expect_column_max_to_be_between": {
+        "expectation_type": "expect_column_max_to_be_between",
+        "kwargs": {
+            "column": "{column_name}",
+            "min_value": "{min_value}",
+            "max_value": "{max_value}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that maximum value of column '{column_name}' is between {min_value} and {max_value}"
