+            }
+        }
+    },
+
+    # Statistical Expectations
+    "expect_column_mean_to_be_between": {
+        "expectation_type": "expect_column_mean_to_be_between",
+        "kwargs": {
+            "column": "{column_name}",
+            "min_value": "{min_value}",
+            "max_value": "{max_value}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that mean of column '{column_name}' is between {min_value} and {max_value}"
+            }
+        }
+    },
+
+    "expect_column_median_to_be_between": {
+        "expectation_type": "expect_column_median_to_be_between",
+        "kwargs": {
+            "column": "{column_name}",
+            "min_value": "{min_value}",
+            "max_value": "{max_value}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that median of column '{column_name}' is between {min_value} and {max_value}"
+            }
+        }
+    },
+
+    # Custom Expectations
+    "expect_column_values_to_be_between": {
+        "expectation_type": "expect_column_values_to_be_between",
+        "kwargs": {
+            "column": "{column_name}",
+            "min_value": "{min_value}",
+            "max_value": "{max_value}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that all values in column '{column_name}' are between {min_value} and {max_value}"
+            }
+        }
+    },
+
+    "expect_table_row_count_to_equal": {
+        "expectation_type": "expect_table_row_count_to_equal",
+        "kwargs": {
+            "value": "{row_count}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that table has exactly {row_count} rows"
+            }
+        }
+    },
+
+    "expect_table_row_count_to_be_between": {
+        "expectation_type": "expect_table_row_count_to_be_between",
+        "kwargs": {
+            "min_value": "{min_value}",
+            "max_value": "{max_value}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Validates that table row count is between {min_value} and {max_value}"
+            }
+        }
+    },
+
+    # Custom complex expectations
+    "expect_compound": {
+        "expectation_type": "expect_compound",
+        "kwargs": {
+            "expectation_config": "{compound_config}"
+        },
+        "meta": {
+            "notes": {
+                "format": "markdown",
+                "content": "Complex validation requiring multiple expectations"
+            }
+        }
+    }
+}
+
+
+def get_template(expectation_type: str) -> Dict[str, Any]:
+    """Get GEX template by expectation type"""
+    template = GEX_TEMPLATES.get(expectation_type)
+    if not template:
+        raise ValueError(f"Unsupported expectation type: {expectation_type}")
+    return json.loads(json.dumps(template))  # Deep copy
+
+
+def get_available_expectations() -> List[str]:
+    """Get list of all supported expectation types"""
+    return list(GEX_TEMPLATES.keys())
+
+
+def populate_template(expectation_type: str, parameters: Dict[str, Any]) -> Dict[str, Any]:
+    """Populate template with actual parameter values"""
+    template = get_template(expectation_type)
+
+    # Convert template to JSON string for substitution
+    template_str = json.dumps(template)
+
+    # Replace placeholders with actual values
+    for key, value in parameters.items():
+        placeholder = "{" + key + "}"
+        if isinstance(value, (list, dict)):
+            value_str = json.dumps(value)
+        else:
+            value_str = str(value)
+        template_str = template_str.replace(placeholder, value_str)
+
+    # Convert back to dict
+    populated_template = json.loads(template_str)
+
+    # Add metadata
+    if "original_sql" in parameters:
+        populated_template["meta"]["original_sql"] = parameters["original_sql"]
+    if "confidence_score" in parameters:
+        populated_template["meta"]["confidence_score"] = parameters["confidence_score"]
+    if "conversion_notes" in parameters:
+        populated_template["meta"]["conversion_notes"] = parameters["conversion_notes"]
+
+    return populated_template
+
+
+def validate_template_parameters(expectation_type: str, parameters: Dict[str, Any]) -> List[str]:
+    """Validate that required parameters are provided for template"""
+    template = get_template(expectation_type)
+    template_str = json.dumps(template)
+
+    # Find all placeholders in template
+    import re
+    placeholders = re.findall(r'\{(\w+)\}', template_str)
+
+    missing_params = []
+    for placeholder in placeholders:
+        if placeholder not in parameters:
+            missing_params.append(placeholder)
+
+    return missing_params
